mapper.select:
SELECT id, product_id, total_stock, available_stock, locked_quantity, version, updated_at
FROM inventory
WHERE product_id = #{productId}

mapper.update:
UPDATE inventory
SET
    available_stock  = available_stock  - #{quantity},
    locked_quantity  = locked_quantity  + #{quantity}
WHERE
    product_id       = #{productId}
    AND available_stock >= #{quantity}

UPDATE inventory
SET
    total_stock     = total_stock    - #{quantity},
    locked_quantity = locked_quantity - #{quantity}
WHERE
    product_id      = #{productId}
    AND locked_quantity >= #{quantity}

UPDATE inventory
SET
    available_stock = available_stock + #{quantity},
    locked_quantity = locked_quantity - #{quantity}
WHERE
    product_id      = #{productId}
    AND locked_quantity >= #{quantity}

UPDATE inventory
SET
    total_stock     = total_stock     + #{addedStock},
    available_stock = available_stock + #{addedStock}
WHERE product_id = #{productId}
